(function (global) {
  const ns = (global.AppBackend = global.AppBackend || {});
  const BACKEND_CONFIG = {
    baseUrl: 'http://localhost:4000',
    apiPrefix: '/api'
  };
  async function apiRequest(endpoint, options = {}) {
    const url = `${BACKEND_CONFIG.baseUrl}${BACKEND_CONFIG.apiPrefix}${endpoint}`;
    const config = {
      method: options.method || 'GET',
      headers: {
        'Content-Type': 'application/json',
        ...options.headers
      },
      ...options
    };
    if (options.body && typeof options.body === 'object') {
      config.body = JSON.stringify(options.body);
    }
    const token = localStorage.getItem('auth_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    try {
      const response = await fetch(url, config);
      const data = await response.json();
      if (!response.ok) {
        throw new Error(data.message || `HTTP ${response.status}`);
      }
      return data;
    } catch (error) {
      console.error('API request failed:', error);
      throw error;
    }
  }
  ns.authApi = {
    async signUp(email, password, fullName) {
      return await apiRequest('/auth/register', {
        method: 'POST',
        body: { email, password, name: fullName }
      });
    },
    async signIn(email, password) {
      const response = await apiRequest('/auth/login', {
        method: 'POST',
        body: { email, password }
      });
      if (response.data && response.data.token) {
        localStorage.setItem('auth_token', response.data.token);
      }
      return response;
    },
    async signOut() {
      localStorage.removeItem('auth_token');
      return { success: true };
    },
    async getCurrentUser() {
      try {
        const response = await apiRequest('/auth/verify-token', {
          method: 'POST'
        });
        return response.data;
      } catch (error) {
        return null;
      }
    }
  };
  ns.catalogApi = {
    async searchProducts(params = {}) {
      const queryParams = new URLSearchParams();
      if (params.query) queryParams.append('query', params.query);
      if (params.categorySlug) queryParams.append('category', params.categorySlug);
      if (params.page) queryParams.append('page', params.page);
      if (params.pageSize) queryParams.append('limit', params.pageSize);
      const response = await apiRequest(`/products/search?${queryParams}`);
      return {
        items: response.data || [],
        page: params.page || 1,
        pageSize: params.pageSize || 12
      };
    },
    async getProductBySlug(slug) {
      const response = await apiRequest(`/products/${slug}`);
      return response.data;
    },
    async getCategories() {
      const response = await apiRequest('/products/categories');
      return response.data || [];
    }
  };
  ns.blogApi = {
    async getPosts(params = {}) {
      const queryParams = new URLSearchParams();
      if (params.page) queryParams.append('page', params.page);
      if (params.limit) queryParams.append('limit', params.limit);
      const response = await apiRequest(`/blog/posts?${queryParams}`);
      return response.data || [];
    },
    async getPostBySlug(slug) {
      const response = await apiRequest(`/blog/posts/${slug}`);
      return response.data;
    },
    async submitComment(postIdOrPayload, comment, authorName, authorEmail) {
      const payload =
        postIdOrPayload && typeof postIdOrPayload === 'object'
          ? postIdOrPayload
          : {
              postId: postIdOrPayload,
              comment,
              authorName,
              authorEmail
            };
      const message = payload.message || payload.comment || '';
      const postSlug = payload.postSlug || null;
      const postId = payload.postId || null;
      return await apiRequest('/blog/comments', {
        method: 'POST',
        body: {
          postId,
          postSlug,
          comment: message,
          message,
          authorName: payload.authorName,
          authorEmail: payload.authorEmail,
          sourceChannel: payload.sourceChannel || 'blog_detail'
        }
      });
    }
  };
  ns.formsApi = {
    async submitInquiry(inquiryData) {
      return await apiRequest('/forms/inquiry', {
        method: 'POST',
        body: inquiryData
      });
    },
    async subscribeToUpdates(email, preferences = {}) {
      return await apiRequest('/forms/subscribe', {
        method: 'POST',
        body: { email, preferences }
      });
    }
  };
  ns.uploadApi = {
    async uploadFile(file, type = 'general') {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('type', type);
      return await apiRequest('/upload', {
        method: 'POST',
        headers: {}, // Let browser set content-type for FormData
        body: formData
      });
    }
  };
  ns.initializeApi = function() {
    console.log('Backend API client initialized for local server at', BACKEND_CONFIG.baseUrl);
  };
  ns.initSupabase = function() {
    const url = window.SUPABASE_URL || window.__SUPABASE_URL;
    const key = window.SUPABASE_ANON_KEY || window.__SUPABASE_ANON_KEY;
    if (!url || !key) return null;
    function createClientFromGlobal() {
      try {
        if (window.supabase && typeof window.supabase.createClient === 'function') {
          ns.supabase = window.supabase.createClient(url, key);
          return ns.supabase;
        }
      } catch (e) {
        console.warn('Supabase global client not ready yet');
      }
      return null;
    }
    const existing = createClientFromGlobal();
    if (existing) return existing;
    return new Promise((resolve, reject) => {
      const scriptId = 'supabase-umd';
      if (document.getElementById(scriptId)) {
        const check = () => {
          const c = createClientFromGlobal();
          if (c) resolve(c);
          else setTimeout(check, 50);
        };
        check();
        return;
      }
      const script = document.createElement('script');
      script.id = scriptId;
      script.src = 'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/dist/umd/supabase.min.js';
      script.onload = () => {
        const client = createClientFromGlobal();
        if (client) resolve(client);
        else reject(new Error('Failed to create Supabase client after script load'));
      };
      script.onerror = (e) => reject(e || new Error('Failed to load Supabase UMD bundle'));
      document.head.appendChild(script);
    });
  };
  ns.getSupabaseClient = function() {
    if (ns.__supabaseClient) return ns.__supabaseClient;
    if (ns.supabase) return ns.supabase;
    if (typeof window !== 'undefined' && (window.SUPABASE_URL || window.__SUPABASE_URL)) {
      const res = ns.initSupabase();
      if (res && typeof res.then === 'function') {
        return {
          _ready: res,
          _errorIfNotReady() {
            throw new Error('Supabase client initializing; await ns.getSupabaseClient()._ready before use');
          }
        };
      }
    }
    if (typeof ns.initSupabase === 'function') {
      const initialized = ns.initSupabase();
      if (initialized && typeof initialized.then === 'function') {
        return {
          _ready: initialized,
          _errorIfNotReady() {
            throw new Error('Supabase client initializing; await ns.getSupabaseClient()._ready before use');
          }
        };
      }
      if (initialized) return initialized;
    }
    return {
      auth: {
        signUp: ns.authApi.signUp,
        signInWithPassword: ns.authApi.signIn,
        signOut: ns.authApi.signOut,
        getUser: ns.authApi.getCurrentUser
      },
      from: function(table) {
        return {
          select: function(columns) {
            return {
              eq: function(column, value) {
                return {
                  single: async function() {
                    console.warn('Mock Supabase query (delegating to local API):', table, columns, column, value);
                    const resp = await ns.apiRequest(`/products/${value}`);
                    return { data: resp.data || null, error: null };
                  }
                };
              }
            };
          }
        };
      },
      rpc: async function(functionName, params) {
        console.warn('Mock Supabase RPC (delegating to local API):', functionName, params);
        const resp = await ns.apiRequest(`/rpc/${functionName}`, {
          method: 'POST',
          body: params
        });
        return { data: resp.data || [], error: null };
      }
    };
  };
})(window);
